  // Variant Operations
  // ---------------------------------------------------------------------------

  /**
   * Creates a product variant
   *
   * @param data - Create data
   * @returns Created variant
   */
  async createVariant(data: CreateVariantData): Promise<ProductVariant> {
    const result = await this.prisma.productVariant.create({
      data: {
        productId: data.productId,
        name: data.name,
        price: new Prisma.Decimal(data.price),
        isDefault: data.isDefault ?? false,
        isAvailable: data.isAvailable ?? true,
        sortOrder: data.sortOrder ?? 0,
      },
    });

    return result as ProductVariant;
  }

  /**
   * Updates a product variant
   *
   * @param id - Variant ID
   * @param productId - Product ID (for ownership verification)
   * @param data - Update data
   * @returns Updated variant
   */
  async updateVariant(
    id: string,
    productId: string,
    data: UpdateVariantData
  ): Promise<ProductVariant> {
    // Verify variant belongs to product
    const variant = await this.prisma.productVariant.findFirst({
      where: { id, productId },
    });

    if (!variant) {
      throw AppException.notFound('ProductVariant', id);
    }

    const result = await this.prisma.productVariant.update({
      where: { id },
      data: {
        ...(data.name !== undefined && { name: data.name }),
        ...(data.price !== undefined && { price: new Prisma.Decimal(data.price) }),
        ...(data.isDefault !== undefined && { isDefault: data.isDefault }),
        ...(data.isAvailable !== undefined && { isAvailable: data.isAvailable }),
        ...(data.sortOrder !== undefined && { sortOrder: data.sortOrder }),
      },
    });

    return result as ProductVariant;
  }

  /**
   * Deletes a product variant
   *
   * @param id - Variant ID
   * @param productId - Product ID (for ownership verification)
   */
  async deleteVariant(id: string, productId: string): Promise<void> {
    // Verify variant belongs to product
    const variant = await this.prisma.productVariant.findFirst({
      where: { id, productId },
    });

    if (!variant) {
      throw AppException.notFound('ProductVariant', id);
    }

    await this.prisma.productVariant.delete({
      where: { id },
    });
  }

  /**
   * Finds all variants for a product
   *
   * @param productId - Product ID
   * @returns Array of variants
   */
  async findVariants(productId: string): Promise<ProductVariant[]> {
    const result = await this.prisma.productVariant.findMany({
      where: { productId },
      orderBy: { sortOrder: 'asc' },
    });

    return result as ProductVariant[];
  }

  /**
   * Sets a variant as default (and unsets others)
   *
   * @param id - Variant ID to set as default
   * @param productId - Product ID
   * @returns Updated variant
   */
  async setDefaultVariant(id: string, productId: string): Promise<ProductVariant> {
    // Verify variant belongs to product
    const variant = await this.prisma.productVariant.findFirst({
      where: { id, productId },
    });

    if (!variant) {
      throw AppException.notFound('ProductVariant', id);
    }

    // Unset any existing default and set the new one
    await this.prisma.$transaction([
      this.prisma.productVariant.updateMany({
        where: { productId, isDefault: true },
        data: { isDefault: false },
      }),
      this.prisma.productVariant.update({
        where: { id },
        data: { isDefault: true },
      }),
    ]);

    // Return updated variant
    const result = await this.prisma.productVariant.findUnique({
      where: { id },
    });

    return result as ProductVariant;
  }

