  // ---------------------------------------------------------------------------
  // Allergen Operations
  // ---------------------------------------------------------------------------

  /**
   * Sets allergens for a product (replaces existing)
   *
   * @param productId - Product ID
   * @param allergenIds - Array of allergen IDs
   */
  async setAllergens(productId: string, allergenIds: string[]): Promise<void> {
    await this.prisma.$transaction([
      // Delete existing associations
      this.prisma.productAllergen.deleteMany({
        where: { productId },
      }),
      // Create new associations
      this.prisma.productAllergen.createMany({
        data: allergenIds.map((allergenId) => ({
          productId,
          allergenId,
        })),
      }),
    ]);
  }

  /**
   * Adds an allergen to a product
   *
   * @param productId - Product ID
   * @param allergenId - Allergen ID
   */
  async addAllergen(productId: string, allergenId: string): Promise<void> {
    // Check if already exists
    const existing = await this.prisma.productAllergen.findUnique({
      where: {
        productId_allergenId: { productId, allergenId },
      },
    });

    if (!existing) {
      await this.prisma.productAllergen.create({
        data: { productId, allergenId },
      });
    }
  }

  /**
   * Removes an allergen from a product
   *
   * @param productId - Product ID
   * @param allergenId - Allergen ID
   */
  async removeAllergen(productId: string, allergenId: string): Promise<void> {
    await this.prisma.productAllergen.deleteMany({
      where: { productId, allergenId },
    });
  }

