  /**
   * Creates or updates nutrition info for a product
   *
   * @param productId - Product ID
   * @param data - Nutrition info data
   * @returns Created/updated nutrition info
   */
  async upsertNutritionInfo(
    productId: string,
    data: Omit<CreateNutritionInfoData, 'productId'>
  ): Promise<NutritionInfo> {
    const result = await this.prisma.nutritionInfo.upsert({
      where: { productId },
      create: {
        productId,
        calories: data.calories ?? null,
        protein: data.protein ? new Prisma.Decimal(data.protein) : null,
        carbohydrates: data.carbohydrates ? new Prisma.Decimal(data.carbohydrates) : null,
        fat: data.fat ? new Prisma.Decimal(data.fat) : null,
        fiber: data.fiber ? new Prisma.Decimal(data.fiber) : null,
        sodium: data.sodium ? new Prisma.Decimal(data.sodium) : null,
        sugar: data.sugar ? new Prisma.Decimal(data.sugar) : null,
        servingSize: data.servingSize ?? null,
        servingUnit: data.servingUnit ?? null,
      },
      update: {
        ...(data.calories !== undefined && { calories: data.calories }),
        ...(data.protein !== undefined && { protein: data.protein ? new Prisma.Decimal(data.protein) : null }),
        ...(data.carbohydrates !== undefined && { carbohydrates: data.carbohydrates ? new Prisma.Decimal(data.carbohydrates) : null }),
        ...(data.fat !== undefined && { fat: data.fat ? new Prisma.Decimal(data.fat) : null }),
        ...(data.fiber !== undefined && { fiber: data.fiber ? new Prisma.Decimal(data.fiber) : null }),
        ...(data.sodium !== undefined && { sodium: data.sodium ? new Prisma.Decimal(data.sodium) : null }),
        ...(data.sugar !== undefined && { sugar: data.sugar ? new Prisma.Decimal(data.sugar) : null }),
        ...(data.servingSize !== undefined && { servingSize: data.servingSize }),
        ...(data.servingUnit !== undefined && { servingUnit: data.servingUnit }),
      },
    });

    return result as NutritionInfo;
  }

  /**
   * Deletes nutrition info for a product
   *
   * @param productId - Product ID
   */
  async deleteNutritionInfo(productId: string): Promise<void> {
    await this.prisma.nutritionInfo.deleteMany({
      where: { productId },
    });
  }

  /**
   * Finds nutrition info for a product
   *
   * @param productId - Product ID
   * @returns Nutrition info or null
   */
  async findNutritionInfo(productId: string): Promise<NutritionInfo | null> {
    const result = await this.prisma.nutritionInfo.findUnique({
      where: { productId },
    });

    return result as NutritionInfo | null;
  }
